using UnityEngine;\n\npublic class FoxCamera : MonoBehaviour {\n    public float lookSpeed = 2.0f;\n    public float bobSpeed = 0.18f;\n    public float bobAmount = 0.2f;\n    private Camera playerCamera;\n    private Vector3 originalCameraPosition;\n    private float timer = 0;\n    \n    void Start() {\n        playerCamera = GetComponent<Camera>();\n        originalCameraPosition = playerCamera.transform.localPosition;\n    }\n    \n    void Update() {\n        // Handle Mouse Look\n        float mouseX = Input.GetAxis("Mouse X") * lookSpeed;\n        float mouseY = Input.GetAxis("Mouse Y") * lookSpeed;\n        transform.localRotation *= Quaternion.Euler(-mouseY, mouseX, 0);\n        \n        // Handle Head Bob\n        if (Input.GetAxis("Vertical") != 0 || Input.GetAxis("Horizontal") != 0) {\n            timer += Time.deltaTime * bobSpeed;\n            float x = Mathf.Cos(timer) * bobAmount;\n            float y = Mathf.Sin(timer) * bobAmount;\n            playerCamera.transform.localPosition = new Vector3(originalCameraPosition.x + x, originalCameraPosition.y + y, originalCameraPosition.z);\n        } else {\n            playerCamera.transform.localPosition = originalCameraPosition;\n            timer = 0;\n        }\n    }\n}